import json, os, sys, time, base64, mimetypes, urllib.request, urllib.error

API_KEY = os.environ.get("VAR_FAL_API_KEY") or os.environ.get("VAR_FAL_KEY") or ""
WORK_DIR = os.environ.get("AT_WORK_DIR") or "/tmp"
ASSETS_DIR = os.environ.get("AT_ASSETS_DIR") or os.path.join(WORK_DIR, "assets")
AVATAR_DIR = os.path.join(ASSETS_DIR, "avatars")

def die(msg, **extra):
    out = {"error": msg}
    out.update(extra)
    print(json.dumps(out)); sys.exit(0)

if not API_KEY:
    die("FAL API key not configured (set fal_api_key or FAL_KEY)")

def http_json(url, payload=None, method=None, timeout=60):
    data = json.dumps(payload).encode() if payload is not None else None
    req = urllib.request.Request(url, data=data, method=method or ("POST" if data else "GET"),
        headers={"Authorization": "Key " + API_KEY, "Content-Type": "application/json"})
    with urllib.request.urlopen(req, timeout=timeout) as r:
        return json.load(r)

def resolve_avatar(ref):
    """Resolve an avatar reference: URL, local path, or library name."""
    if not ref:
        return ref
    if ref.startswith(("http://", "https://", "data:")):
        return ref
    if os.path.isfile(os.path.expanduser(ref)):
        return os.path.expanduser(ref)
    # Library lookup by name/slug: avatars/<slug>.{png,jpg,jpeg,webp}
    slug = ref.strip().lower().replace(" ", "-")
    for ext in ("png", "jpg", "jpeg", "webp"):
        p = os.path.join(AVATAR_DIR, slug + "." + ext)
        if os.path.isfile(p):
            return p
    manifest = os.path.join(AVATAR_DIR, slug + ".json")
    if os.path.isfile(manifest):
        try:
            m = json.load(open(manifest))
            if m.get("file") and os.path.isfile(m["file"]):
                return m["file"]
        except Exception:
            pass
    die("avatar not found: %r (not a URL, file, or library name; use list_avatars)" % ref)

def to_fal_url(path_or_url):
    """Return a URL FAL can fetch: pass URLs through, upload local files to
    the FAL CDN, fall back to a base64 data URI."""
    if path_or_url.startswith(("http://", "https://", "data:")):
        return path_or_url
    p = os.path.expanduser(path_or_url)
    if not os.path.isfile(p):
        die("file not found: " + p)
    ctype = mimetypes.guess_type(p)[0] or "application/octet-stream"
    blob = open(p, "rb").read()
    try:
        init = http_json("https://rest.alpha.fal.ai/storage/upload/initiate?storage_type=fal-cdn-v3",
                         {"content_type": ctype, "file_name": os.path.basename(p)}, timeout=30)
        up = urllib.request.Request(init["upload_url"], data=blob,
                                    headers={"Content-Type": ctype}, method="PUT")
        with urllib.request.urlopen(up, timeout=600):
            pass
        return init["file_url"]
    except Exception:
        if len(blob) > 20 * 1024 * 1024:
            die("CDN upload failed and file too large (>20MB) for inline data URI: " + p)
        return "data:" + ctype + ";base64," + base64.b64encode(blob).decode()

def queue_run(model, payload, poll_minutes=25):
    """Submit to queue.fal.run and poll until completion."""
    sub = http_json("https://queue.fal.run/" + model, payload, timeout=60)
    req_id = sub.get("request_id")
    if not req_id:
        die("FAL submit failed", raw=str(sub)[:800])
    status_url = sub.get("status_url") or "https://queue.fal.run/%s/requests/%s/status" % (model, req_id)
    resp_url = sub.get("response_url") or "https://queue.fal.run/%s/requests/%s" % (model, req_id)
    deadline = time.time() + poll_minutes * 60
    while time.time() < deadline:
        time.sleep(10)
        try:
            st = http_json(status_url, timeout=30)
        except Exception:
            continue
        status = st.get("status", "")
        if status == "COMPLETED":
            return http_json(resp_url, timeout=60), req_id
        if status in ("FAILED", "ERROR"):
            die("FAL job failed", status=status, request_id=req_id)
    die("FAL job timed out", request_id=req_id, status_url=status_url, response_url=resp_url,
        hint="Retry, or poll the status_url manually with the API key.")

def download(url, out_path):
    req = urllib.request.Request(url)
    with urllib.request.urlopen(req, timeout=600) as r, open(out_path, "wb") as f:
        while True:
            chunk = r.read(1 << 20)
            if not chunk:
                break
            f.write(chunk)
    return os.path.getsize(out_path)

def save_to_library(src_path, name, description="", source_url=""):
    os.makedirs(AVATAR_DIR, exist_ok=True)
    slug = name.strip().lower().replace(" ", "-")
    ext = os.path.splitext(src_path)[1].lstrip(".") or "png"
    dest = os.path.join(AVATAR_DIR, slug + "." + ext)
    if os.path.abspath(src_path) != os.path.abspath(dest):
        import shutil
        shutil.copyfile(src_path, dest)
    manifest = {
        "name": name, "slug": slug, "file": dest, "description": description,
        "source_url": source_url,
        "created_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
    }
    with open(os.path.join(AVATAR_DIR, slug + ".json"), "w") as f:
        json.dump(manifest, f, indent=1)
    return manifest

def uid():
    import uuid
    return uuid.uuid4().hex[:10]

prompt = os.environ.get("ARG_PROMPT", "")
ref = os.environ.get("ARG_REFERENCE_IMAGE", "")
ar = os.environ.get("ARG_ASPECT_RATIO", "3:4")
save_as = os.environ.get("ARG_SAVE_AS", "")
desc = os.environ.get("ARG_DESCRIPTION", "")
if not prompt:
    die("prompt is required")

payload = {"prompt": prompt, "aspect_ratio": ar, "output_format": "png", "num_images": 1}
model = "fal-ai/nano-banana-2"
if ref:
    src = resolve_avatar(ref)
    payload["image_urls"] = [to_fal_url(src)]
    model = "fal-ai/nano-banana-2/edit"

res, req_id = queue_run(model, payload, poll_minutes=10)
imgs = res.get("images") or []
if not imgs or not imgs[0].get("url"):
    die("FAL returned no image", request_id=req_id)
url = imgs[0]["url"]
out = os.path.join(WORK_DIR, "avatar-%s.png" % uid())
os.makedirs(WORK_DIR, exist_ok=True)
size = download(url, out)
result = {"image_file": out, "image_url": url, "size_bytes": size, "model": model, "request_id": req_id}
if save_as:
    result["saved"] = save_to_library(out, save_as, desc, url)
print(json.dumps(result))

